const sd = $getWorkflowStaticData('global');
sd.bearbeitet = sd.bearbeitet || [];
const setup = $('⚙️ Setup').first().json;
const checkouts = $json.checkouts || [];
const jetzt = Date.now();
const raus = [];

for (const c of checkouts) {
  if (!c.email) continue;
  if (sd.bearbeitet.includes(c.id)) continue;
  const alterMs = jetzt - new Date(c.created_at).getTime();
  // Nur Warenkörbe zwischen 1h und 24h alt
  if (alterMs < 60 * 60 * 1000 || alterMs > 24 * 60 * 60 * 1000) continue;

  const artikel = (c.line_items || []).map(li => li.quantity + 'x ' + li.title).join(', ');
  const vorname = (c.customer && c.customer.first_name) || '';

  const prompt = 'Du bist E-Mail-Marketing-Profi fuer den Onlineshop "' + setup.SHOP_NAME + '".\n' +
    'Ein Kunde hat seinen Warenkorb stehen lassen. Schreibe eine kurze, persoenliche Rueckhol-E-Mail auf Deutsch (Du-Form), maximal 120 Woerter Text.\n\n' +
    'Daten:\n' +
    '- Vorname: ' + (vorname || 'unbekannt (dann neutral anreden)') + '\n' +
    '- Artikel im Warenkorb: ' + artikel + '\n' +
    '- Warenwert: ' + c.total_price + ' ' + c.currency + '\n' +
    '- Rabattcode: ' + setup.RABATT_CODE + ' (' + setup.RABATT_PROZENT + '% Rabatt)\n' +
    '- Checkout-Link: ' + c.abandoned_checkout_url + '\n\n' +
    'Anforderungen: Rabattcode prominent zeigen, ein klarer Call-to-Action-Button (als <a> mit Inline-Button-Styling) der zum Checkout-Link fuehrt, leichte Dringlichkeit (Code nur 24h gueltig), kein Spam-Ton, mobiltauglich mit Inline-CSS.\n' +
    'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "<komplettes E-Mail-HTML>"}';

  raus.push({ json: {
    checkout_id: c.id,
    email: c.email,
    vorname: vorname,
    summe: c.total_price + ' ' + c.currency,
    prompt: prompt
  }});
  sd.bearbeitet.push(c.id);
}

if (sd.bearbeitet.length > 500) sd.bearbeitet = sd.bearbeitet.slice(-500);
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Du hast etwas im Warenkorb vergessen 🛒', html: text };
}
const orig = $('🧠 Filtern & Prompt bauen').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger: empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html
}};
